#!/usr/bin/env python3
# -*- coding: utf-8 -*-

"""
DeepSeek AI Агент для Termux
Автономный AI-ассистент с полным доступом к Termux
"""

import os
import sys
import json
import subprocess
import readline
import shlex
from datetime import datetime
from pathlib import Path

class DeepSeekAgent:
    def __init__(self):
        self.name = "DeepSeek Agent"
        self.version = "1.0.0"
        self.history = []
        self.learned_patterns = {}
        self.current_dir = os.getcwd()
        self.project_path = "/storage/emulated/0/Android/data/com.termux/files/home"

    def execute_command(self, command):
        """Выполняет команду в Termux"""
        try:
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=30
            )
            return {
                "stdout": result.stdout,
                "stderr": result.stderr,
                "returncode": result.returncode
            }
        except subprocess.TimeoutExpired:
            return {"stdout": "", "stderr": "Command timed out", "returncode": -1}
        except Exception as e:
            return {"stdout": "", "stderr": str(e), "returncode": -1}

    def analyze_project(self):
        """Анализирует текущий проект"""
        print("🔍 Анализ проекта...")

        # Получаем структуру
        result = self.execute_command(f"cd {self.project_path} && find . -type f | head -50")
        print(f"📁 Структура проекта:\n{result['stdout']}")

        # Анализируем файлы
        result = self.execute_command(f"cd {self.project_path} && find . -type f \\( -name '*.kt' -o -name '*.xml' -o -name '*.gradle*' \\) -exec wc -l {} \\; | sort -rn")
        print(f"📊 Статистика файлов:\n{result['stdout']}")

        return result['stdout']

    def read_file(self, filepath):
        """Читает содержимое файла"""
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                return f.read()
        except Exception as e:
            return f"Ошибка чтения файла: {e}"

    def save_file(self, filepath, content):
        """Сохраняет содержимое в файл"""
        try:
            with open(filepath, 'w', encoding='utf-8') as f:
                f.write(content)
            return True
        except Exception as e:
            print(f"Ошибка сохранения: {e}")
            return False

    def interactive_shell(self):
        """Интерактивная оболочка агента"""
        print(f"\n🤖 {self.name} v{self.version}")
        print("=" * 50)
        print("Доступные команды:")
        print("  /analyze  - Анализ проекта")
        print("  /read     - Чтение файла")
        print("  /save     - Сохранение файла")
        print("  /exec     - Выполнить команду")
        print("  /help     - Помощь")
        print("  /exit     - Выход")
        print("=" * 50)

        while True:
            try:
                cmd = input(f"\n{self.name}> ").strip()

                if cmd == "/exit":
                    print("👋 До свидания!")
                    break
                elif cmd == "/analyze":
                    self.analyze_project()
                elif cmd.startswith("/read "):
                    filepath = cmd[6:].strip()
                    content = self.read_file(filepath)
                    print(content)
                elif cmd.startswith("/save "):
                    parts = cmd[6:].strip().split(" ", 1)
                    if len(parts) == 2:
                        filepath, content = parts
                        if self.save_file(filepath, content):
                            print(f"✅ Файл сохранен: {filepath}")
                elif cmd.startswith("/exec "):
                    command = cmd[6:].strip()
                    result = self.execute_command(command)
                    if result['stdout']:
                        print(result['stdout'])
                    if result['stderr']:
                        print(f"⚠️ Ошибка: {result['stderr']}")
                elif cmd == "/help":
                    print("Команды:")
                    print("  /analyze              - Анализ проекта")
                    print("  /read <путь>         - Чтение файла")
                    print("  /save <путь> <текст> - Сохранение файла")
                    print("  /exec <команда>      - Выполнить команду")
                    print("  /help                - Помощь")
                    print("  /exit                - Выход")
                elif cmd:
                    # Выполняем как команду Termux
                    result = self.execute_command(cmd)
                    if result['stdout']:
                        print(result['stdout'])
                    if result['stderr']:
                        print(f"⚠️: {result['stderr']}")

            except KeyboardInterrupt:
                print("\n👋 До свидания!")
                break
            except Exception as e:
                print(f"❌ Ошибка: {e}")

def main():
    agent = DeepSeekAgent()

    if len(sys.argv) > 1:
        # Режим одной команды
        command = " ".join(sys.argv[1:])
        result = agent.execute_command(command)
        if result['stdout']:
            print(result['stdout'])
        if result['stderr']:
            print(f"⚠️: {result['stderr']}")
    else:
        # Интерактивный режим
        agent.interactive_shell()

if __name__ == "__main__":
    main()
EOF
